/* ===============================
   CAA (Centralised Acid & Alkaline)
   =============================== */

.caa-card { }

.caa-body{
  display: block !important;     /* override flex from .cpd-card-body */
  width: 100%;
}

.caa-grid{
  display: grid;
  grid-template-columns: repeat(4, minmax(0, 1fr));
  gap: 10px 10px;
  width: 100%;
  align-items: stretch;
}

/* Row 1 tanks (pill style like your sketch) */
.caa-tank{
  height: 44px;
  border-radius: 14px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-weight: 900;
  letter-spacing: 0.8px;
  border: 1px solid rgba(159,213,255,0.25);
  box-shadow: inset 0 0 10px rgba(0,0,0,0.35), 0 3px 10px rgba(0,0,0,0.55);
  color: #041019;
  text-transform: uppercase;
}

.caa-acid{
  background: linear-gradient(145deg, #0e6742, #0e6742);
  box-shadow: 0 0 10px rgba(255,77,77,0.55);
}

.caa-alk{
  background: linear-gradient(145deg, #1e90ff, #0b5ed7);
  box-shadow: 0 0 10px rgba(30,144,255,0.55);
}

/* Row 2 supply boxes */
.caa-supply{
  background: rgba(10,25,45,0.75);
  border: 1px solid rgba(159,213,255,0.18);
  border-radius: 14px;
  padding: 8px 10px 10px;
  box-shadow: inset 0 0 10px rgba(0,0,0,0.35);
}

.caa-supply-top{
  display: flex;
  justify-content: space-between;
  align-items: baseline;
  gap: 10px;
  margin-bottom: 6px;
}

.caa-supply-label{
  font-size: 10px;
  font-weight: 900;
  letter-spacing: 0.8px;
  color: #9fd5ff;
}

.caa-supply-val{
  font-size: 12px;
  font-weight: 900;
  color: #e6f4ff;
}

/* Bar */
.caa-bar{
  position: relative;
  height: 14px;
  border-radius: 999px;
  overflow: hidden;
  background: rgba(255,255,255,0.10);
  border: 1px solid rgba(255,255,255,0.10);
  box-shadow: inset 0 0 10px rgba(0,0,0,0.35);
}

.caa-bar-fill{
  height: 100%;
  width: calc(var(--pct, 0) * 1%);
  border-radius: 999px;
  box-shadow: 0 0 10px rgba(0,0,0,0.35);
}

/* Acid 1 = GREEN */
.caa-bar-green{
  background: linear-gradient(90deg,#00c777,#00ff9c);
}

/* Acid 2 = RED */
.caa-bar-red{
  background: linear-gradient(90deg,#ff4d4d,#d82424);
}

/* Alkaline 1 = RED */
.caa-bar-red{
  background: linear-gradient(90deg,#ff4d4d,#d82424);
}

/* Alkaline 2 = GREEN */
.caa-bar-green{
  background: linear-gradient(90deg,#00c777,#00ff9c);
}
/*

/* Min/Max labels under bar */
.caa-bar-minmax{
  display: flex;
  justify-content: space-between;
  font-size: 9px;
  font-weight: 800;
  color: rgba(230,244,255,0.75);
