.alarm-warning { border-color: rgba(249,212,35,0.55); box-shadow: 0 0 10px rgba(249,212,35,0.18), inset 0 0 10px rgba(0,0,0,0.35); }
.alarm-info    { border-color: rgba(30,144,255,0.55); box-shadow: 0 0 10px rgba(30,144,255,0.18), inset 0 0 10px rgba(0,0,0,0.35); }
.alarm-ack     { border-color: rgba(0,255,156,0.45); box-shadow: 0 0 10px rgba(0,255,156,0.12), inset 0 0 10px rgba(0,0,0,0.35); }

/* list header */
.alarm-list-head{
  display:grid;
  grid-template-columns: 70px 85px 1fr 90px 110px;
  gap:8px;
  padding: 8px 10px;
  border-radius: 12px;
  background: rgba(255,255,255,0.04);
  border: 1px solid rgba(159,213,255,0.10);
