  overflow:auto;
  padding-right: 4px;
}

/* each row */
.alarm-row{
  display:grid;
  grid-template-columns: 70px 85px 1fr 90px 110px;
  gap:8px;
  align-items:center;
  padding: 9px 10px;
  border-radius: 12px;
  background: rgba(10,25,45,0.70);
