function resetDashboardState() {
  // Remove disabled style from all cards
  const allCards = htmlNode.querySelectorAll(".cpd-card");
  allCards.forEach(card => {
    card.classList.remove("disabled-card");
  });

  // Remove disabled style from special cards
  setCardEnabled("polymerCard");
  setCardEnabled("coatingCard");
  setCardEnabled("storageCard");

  // Reset subtitle
  const subtitle = htmlNode.getElementById("plantSubtitle");
  if (subtitle) {
    subtitle.textContent = `PLANT ${plantNo} COMPOUNDING`;
  }

  // Reset CAA tank colors
  const caaTanks = htmlNode.querySelectorAll(".caa-tank");
  if (caaTanks.length >= 4) {
    caaTanks[0].className = "caa-tank caa-green";
    caaTanks[1].className = "caa-tank caa-grey";
    caaTanks[2].className = "caa-tank caa-grey";
    caaTanks[3].className = "caa-tank caa-green";
  }

  // Reset CAA lower panels
  const caaPanels = htmlNode.querySelectorAll(".caa-supply");
  if (caaPanels.length >= 4) {
    caaPanels[0].className = "caa-supply caa-panel-green";
    caaPanels[1].className = "caa-supply caa-panel-grey";
    caaPanels[2].className = "caa-supply caa-panel-grey";
    caaPanels[3].className = "caa-supply caa-panel-green";
  }

  // Reset CAA values
  const caaValues = htmlNode.querySelectorAll(".caa-value");
  const defaultCAA = ["570 cm", "0.92 bar", "0 cm", "0 bar", "0 cm", "0 bar", "555 cm", "0.67 bar"];
  caaValues.forEach((el, i) => {
    el.textContent = defaultCAA[i] || "--";
  });

  // Reset alarm summary
  const alarmVals = htmlNode.querySelectorAll(".alarm-kpi-val");
  renderRealAlarms();

}

